import os, pathlib
root=pathlib.Path('/tmp/matt-skills')
print('FILES')
for p in sorted(root.rglob('*')):
    if p.is_file(): print(p.relative_to(root))
print('\nSKILL SUMMARIES')
for md in sorted((root/'skills').rglob('SKILL.md')):
    text=md.read_text(errors='ignore')
    first=' '.join(text.strip().split('\n')[:8])[:500]
    print('\n##', md.relative_to(root)); print(first)
